const state = {
  search: "",
  category: "weakauras"
};

const elements = {
  searchInput: document.getElementById("searchInput"),
  categoryTabs: document.getElementById("categoryTabs"),
  importsGrid: document.getElementById("importsGrid"),
  emptyState: document.getElementById("emptyState"),
  copyToast: document.getElementById("copyToast"),
  toastMessage: document.getElementById("toastMessage")
};

const toast = bootstrap.Toast.getOrCreateInstance(elements.copyToast, { delay: 2000 });

bindEvents();
render();

function bindEvents() {
  elements.searchInput.addEventListener("input", (event) => {
    state.search = event.target.value.trim().toLowerCase();
    render();
  });

  elements.categoryTabs.addEventListener("click", (event) => {
    const button = event.target.closest("[data-category]");
    if (!button) return;

    state.category = button.dataset.category;

    [...elements.categoryTabs.querySelectorAll(".category-tab")].forEach((tab) => {
      tab.classList.toggle("active", tab === button);
    });

    render();
  });

  elements.importsGrid.addEventListener("click", async (event) => {
    const copyButton = event.target.closest("[data-copy-index]");
    if (!copyButton) return;

    const index = Number(copyButton.dataset.copyIndex);
    const entry = getVisibleImports()[index];
    if (!entry) return;

    await copyText(entry.importText, `${entry.title} copied.`);
  });
}

function getVisibleImports() {
  return importsData.filter((entry) => {
    const matchesCategory = entry.category === state.category;
    const haystack = [entry.title, entry.importText, formatCategory(entry.category)].join(" ").toLowerCase();
    const matchesSearch = !state.search || haystack.includes(state.search);
    return matchesCategory && matchesSearch;
  });
}

function render() {
  const visibleImports = getVisibleImports();
  elements.emptyState.classList.toggle("d-none", visibleImports.length > 0);
  elements.importsGrid.innerHTML = visibleImports.map((entry, index) => renderCard(entry, index)).join("");
}

function renderCard(entry, index) {
  return `
    <div class="col-12 col-xl-6">
      <article class="import-card">
        <div class="import-card-inner">
          <h2 class="card-title">${escapeHtml(entry.title)}</h2>
          <textarea class="import-box" readonly>${escapeHtml(entry.importText)}</textarea>
          <div class="card-actions">
            <button class="copy-btn" type="button" data-copy-index="${index}">Copy Import</button>
          </div>
        </div>
      </article>
    </div>
  `;
}

function formatCategory(category) {
  const labels = {
    weakauras: "WeakAuras",
    profiles: "Addon Profiles",
    macros: "Macros",
    commands: "Commands"
  };
  return labels[category] || category;
}

async function copyText(text, message) {
  try {
    await navigator.clipboard.writeText(text);
    showToast(message);
  } catch {
    const helper = document.createElement("textarea");
    helper.value = text;
    document.body.appendChild(helper);
    helper.select();
    document.execCommand("copy");
    helper.remove();
    showToast(message);
  }
}

function showToast(message) {
  elements.toastMessage.textContent = message;
  toast.show();
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}
